






























































import { Component, Vue } from "vue-property-decorator";

import LightBox from "vue-image-lightbox";

import { imageNames } from "./image_names";

import "vue-image-lightbox/dist/vue-image-lightbox.min.css";

@Component({
  components: {
    LightBox
  }
})
export default class Gallery extends Vue {
  $refs!: {
    lightbox: LightBox;
  };

  data() {
    return {
      imageNames,
      currentImageIndex: imageNames.indexOf(this.$route.params.imageId)
    };
  }

  mounted() {
    if (
      this.$route.params.imageId &&
      !imageNames.includes(this.$route.params.imageId)
    ) {
      this.$router.replace("/gallery");
    }
    // When lazy loading is finished, add a click event to the LightBox image
    // that goes to the next image. Events that are added before lazy loading
    // is done will be removed because the element is re-added to the DOM.
    // LightBox doesn't have any options for image click events, and none of
    // its emitted events work for this use case.
    this.$Lazyload.$on("loaded", this.handleImageLoaded);
  }

  beforeDestroy() {
    this.$Lazyload.$off("loaded");
  }

  handleClickGalleryThumbnail(index: number) {
    this.$refs.lightbox.showImage(index);
    this.handleImageChanged(index);
  }

  handleImageClosed() {
    if (this.$route.params.imageId) {
      this.$router.replace("/gallery");
    }
  }

  handleImageChanged(index: number) {
    const name = imageNames[index];
    if (name && name !== this.$route.params.imageId) {
      this.$router.replace(`/gallery/${name}`).catch(() => {});
    }
  }

  handleImageLoaded() {
    // Add a click event to go to the next image.
    const lightboxImage = document.querySelector<HTMLImageElement>(
      ".vue-lb-modal-image"
    );
    if (lightboxImage) {
      lightboxImage.removeEventListener("click", this.handleNextImage);
      lightboxImage.addEventListener("click", this.handleNextImage);
    }
  }

  handleNextImage() {
    this.$refs.lightbox.nextImage();
  }

  getThumbnailSrc(name: string): NodeRequire {
    return require("../../assets/thumbnails/" + name + ".jpg");
  }

  getImageSrc(name: string): NodeRequire {
    return require("../../assets/images/" + name + ".jpg");
  }
}
